import pygame
import numpy as np
import sys
import random
import math
import sounddevice as sd
import threading

# ─────────────────────────────────────────────
#  Audio helpers  (sounddevice OutputStream)
# ─────────────────────────────────────────────
SAMPLE_RATE = 44100

def play_tone(frequency, duration_s, volume=0.4, waveform='sine'):
    """Play a tone in a background thread so the game never blocks."""
    def _play():
        frames = int(SAMPLE_RATE * duration_s)
        t = np.linspace(0, duration_s, frames, endpoint=False)
        if waveform == 'sine':
            wave = np.sin(2 * np.pi * frequency * t)
        elif waveform == 'square':
            wave = np.sign(np.sin(2 * np.pi * frequency * t))
        elif waveform == 'sawtooth':
            wave = 2 * (t * frequency - np.floor(t * frequency + 0.5))
        else:
            wave = np.sin(2 * np.pi * frequency * t)
        wave = (wave * volume).astype(np.float32)
        # OutputStream needs shape (frames, channels)
        stereo = np.column_stack([wave, wave])
        try:
            sd.play(stereo, samplerate=SAMPLE_RATE)
            sd.wait()
        except Exception:
            pass
    threading.Thread(target=_play, daemon=True).start()

def play_melody(notes, volume=0.35):
    """notes = list of (freq, duration_s)"""
    def _play():
        for freq, dur in notes:
            frames = int(SAMPLE_RATE * dur)
            t = np.linspace(0, dur, frames, endpoint=False)
            wave = np.sin(2 * np.pi * freq * t) * volume
            # fade out last 10 %
            fade = int(frames * 0.1)
            wave[-fade:] *= np.linspace(1, 0, fade)
            stereo = np.column_stack([wave.astype(np.float32),
                                      wave.astype(np.float32)])
            try:
                sd.play(stereo, samplerate=SAMPLE_RATE)
                sd.wait()
            except Exception:
                pass
    threading.Thread(target=_play, daemon=True).start()

# ─────────────────────────────────────────────
#  Colour palette
# ─────────────────────────────────────────────
BG          = (10,  10,  30)
GRID_COL    = (30,  30,  60)
WHITE       = (255, 255, 255)
CYAN        = (0,   220, 255)
