PANEL_W     = 260
WIN_W       = COLS * CELL + 2 * MARGIN + PANEL_W
WIN_H       = ROWS * CELL + 2 * MARGIN + 60   # +60 for top bar
FPS         = 60

GRID_X      = MARGIN
