# ─────────────────────────────────────────────
#  Particle system
# ─────────────────────────────────────────────
class Particle:
    def __init__(self, x, y, colour):
        self.x  = x
        self.y  = y
        self.vx = random.uniform(-4, 4)
        self.vy = random.uniform(-6, 1)
        self.colour = colour
        self.life   = random.randint(30, 60)
        self.max_life = self.life
        self.r = random.randint(3, 7)

    def update(self):
        self.x  += self.vx
        self.y  += self.vy
        self.vy += 0.2
        self.life -= 1

    def draw(self, surf):
        alpha = int(255 * self.life / self.max_life)
        col   = (*self.colour[:3], alpha)
        s = pygame.Surface((self.r*2, self.r*2), pygame.SRCALPHA)
        pygame.draw.circle(s, col, (self.r, self.r), self.r)
        surf.blit(s, (int(self.x - self.r), int(self.y - self.r)))

# ─────────────────────────────────────────────
#  Orb (gem) class
# ─────────────────────────────────────────────
class Orb:
    def __init__(self, col_idx):
        self.col_idx = col_idx
        self.colour  = ORB_COLOURS[col_idx]
        self.y_off   = 0.0   # for drop animation
        self.pulse   = random.uniform(0, math.pi * 2)

    def update(self):
        self.pulse += 0.05
        if self.y_off > 0:
            self.y_off = max(0, self.y_off - 8)

    def draw(self, surf, cx, cy, selected=False, hint=False):
        r = CELL // 2 - 6
        glow_r = r + 4 + int(3 * math.sin(self.pulse))

        # glow
        glow_col = (*self.colour, 60)
        gs = pygame.Surface((glow_r*2+4, glow_r*2+4), pygame.SRCALPHA)
        pygame.draw.circle(gs, glow_col, (glow_r+2, glow_r+2), glow_r)
        surf.blit(gs, (cx - glow_r - 2, cy - glow_r - 2))

        # body
        pygame.draw.circle(surf, self.colour, (cx, cy), r)

        # shine
        shine_pos = (cx - r//3, cy - r//3)
        pygame.draw.circle(surf, WHITE, shine_pos, r//4)

        # selected ring
        if selected:
            pygame.draw.circle(surf, WHITE, (cx, cy), r + 4, 3)
        if hint:
            pygame.draw.circle(surf, YELLOW, (cx, cy), r + 6, 2)

# ─────────────────────────────────────────────
#  Main Game class
# ─────────────────────────────────────────────
class NovaCrush:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WIN_W, WIN_H))
        pygame.display.set_caption("NOVA CRUSH  -  Orb Matching Puzzle")
        self.clock  = pygame.time.Clock()

        self.font_big   = pygame.font.SysFont("consolas", 36, bold=True)
        self.font_med   = pygame.font.SysFont("consolas", 22, bold=True)
        self.font_small = pygame.font.SysFont("consolas", 16)

        self.state = "rules"   # rules | playing | gameover | win
        self.init_game()

    # ── initialise / reset ──────────────────────────────────────────
    def init_game(self):
        self.grid      = [[None]*COLS for _ in range(ROWS)]
        self.selected  = None   # (r, c)
        self.score     = 0
        self.level     = 1
        self.combo     = 0
        self.moves     = 20 + (self.level - 1) * 5
        self.particles = []
        self.animating = False
        self.hint_pair = None
        self.hint_timer= 0
        self.score_popups = []   # [(text, x, y, life)]

        self.fill_grid()
        # clear any starting matches
        for _ in range(10):
            matches = self.find_matches()
            if not matches:
                break
            self.remove_matches(matches, silent=True)
            self.drop_orbs(silent=True)
            self.fill_empty(silent=True)

    def random_orb(self):
        # fewer colours on early levels → easier
        n_cols = min(3 + self.level, len(ORB_COLOURS))
        return Orb(random.randint(0, n_cols - 1))

    def fill_grid(self):
        for r in range(ROWS):
            for c in range(COLS):
                if self.grid[r][c] is None:
                    self.grid[r][c] = self.random_orb()

    def fill_empty(self, silent=False):
        for r in range(ROWS):
            for c in range(COLS):
                if self.grid[r][c] is None:
                    orb = self.random_orb()
                    orb.y_off = (ROWS - r) * CELL
                    self.grid[r][c] = orb

    # ── match finding ───────────────────────────────────────────────
    def find_matches(self):
        matched = set()
        # horizontal
        for r in range(ROWS):
            for c in range(COLS - MIN_MATCH + 1):
                ci = self.grid[r][c].col_idx if self.grid[r][c] else -1
                if ci == -1:
                    continue
                run = [self.grid[r][c2] for c2 in range(c, COLS)
                       if self.grid[r][c2] and self.grid[r][c2].col_idx == ci]
                # find consecutive
                streak = 1
                for c2 in range(c+1, COLS):
                    if self.grid[r][c2] and self.grid[r][c2].col_idx == ci:
                        streak += 1
                    else:
                        break
                if streak >= MIN_MATCH:
                    for dc in range(streak):
                        matched.add((r, c+dc))
        # vertical
        for c in range(COLS):
            for r in range(ROWS - MIN_MATCH + 1):
                ci = self.grid[r][c].col_idx if self.grid[r][c] else -1
                if ci == -1:
                    continue
                streak = 1
                for r2 in range(r+1, ROWS):
                    if self.grid[r2][c] and self.grid[r2][c].col_idx == ci:
                        streak += 1
                    else:
                        break
                if streak >= MIN_MATCH:
                    for dr in range(streak):
                        matched.add((r+dr, c))
        return matched

    def remove_matches(self, matches, silent=False):
        for (r, c) in matches:
            orb = self.grid[r][c]
            if orb and not silent:
                cx = GRID_X + c * CELL + CELL // 2
                cy = GRID_Y + r * CELL + CELL // 2
                for _ in range(12):
                    self.particles.append(Particle(cx, cy, orb.colour))
            self.grid[r][c] = None

    def drop_orbs(self, silent=False):
        for c in range(COLS):
            col = [self.grid[r][c] for r in range(ROWS) if self.grid[r][c]]
            for r in range(ROWS):
                self.grid[r][c] = None
            for i, orb in enumerate(col):
                self.grid[ROWS - len(col) + i][c] = orb

    # ── hint finder ─────────────────────────────────────────────────
    def find_hint(self):
        """Return a valid swap pair (r1,c1,r2,c2) or None."""
        for r in range(ROWS):
            for c in range(COLS):
                for dr, dc in [(0,1),(1,0)]:
                    r2, c2 = r+dr, c+dc
                    if 0 <= r2 < ROWS and 0 <= c2 < COLS:
                        self.swap(r, c, r2, c2)
                        m = self.find_matches()
                        self.swap(r, c, r2, c2)
                        if m:
                            return (r, c, r2, c2)
        return None

    # ── swap ────────────────────────────────────────────────────────
    def swap(self, r1, c1, r2, c2):
        self.grid[r1][c1], self.grid[r2][c2] = \
            self.grid[r2][c2], self.grid[r1][c1]

    def try_swap(self, r1, c1, r2, c2):
        if abs(r1-r2) + abs(c1-c2) != 1:
            return False
        self.swap(r1, c1, r2, c2)
        matches = self.find_matches()
        if matches:
            self.moves -= 1
            self.combo  = 0
            self.resolve_cascade(matches)
            play_tone(440, 0.12)
            return True
        else:
            self.swap(r1, c1, r2, c2)   # undo
            play_tone(200, 0.1, waveform='square')
            return False

    def resolve_cascade(self, matches):
        """Remove matches, drop, refill, repeat."""
        while matches:
            self.combo += 1
            pts = len(matches) * POINTS_PER + (self.combo - 1) * COMBO_BONUS
            self.score += pts

            # score popup
            if matches:
                cells = list(matches)
                mr = sum(r for r,c in cells) // len(cells)
                mc = sum(c for r,c in cells) // len(cells)
                px = GRID_X + mc * CELL + CELL // 2
                py = GRID_Y + mr * CELL + CELL // 2
                txt = f"+{pts}"
                if self.combo > 1:
                    txt += f"  x{self.combo} COMBO!"
                self.score_popups.append([txt, px, py, 60])

            # sound: higher pitch for bigger combos
            freq = 330 + self.combo * 80
            play_tone(min(freq, 1200), 0.15)

            self.remove_matches(matches)
            self.drop_orbs()
            self.fill_empty()
            matches = self.find_matches()

        # level up?
        if self.score >= self.level * LEVEL_GOAL:
            if self.level < MAX_LEVEL:
                self.level += 1
                self.moves += 15
                play_melody([(523,0.15),(659,0.15),(784,0.15),(1047,0.3)])
            else:
                self.state = "win"
                play_melody([(523,0.1),(659,0.1),(784,0.1),(1047,0.1),
                             (1319,0.2),(1047,0.1),(1319,0.4)])

        if self.moves <= 0 and self.state == "playing":
            self.state = "gameover"
            play_melody([(300,0.2),(250,0.2),(200,0.4)])

    # ── cell from pixel ─────────────────────────────────────────────
    def pixel_to_cell(self, px, py):
        c = (px - GRID_X) // CELL
        r = (py - GRID_Y) // CELL
        if 0 <= r < ROWS and 0 <= c < COLS:
            return r, c
        return None

    # ── update ──────────────────────────────────────────────────────
    def update(self):
        for r in range(ROWS):
            for c in range(COLS):
                if self.grid[r][c]:
                    self.grid[r][c].update()

        self.particles = [p for p in self.particles if p.life > 0]
        for p in self.particles:
            p.update()

        self.score_popups = [(t,x,y,l-1) for t,x,y,l in self.score_popups if l>0]

        if self.hint_timer > 0:
            self.hint_timer -= 1
            if self.hint_timer == 0:
                self.hint_pair = None

    # ── draw helpers ────────────────────────────────────────────────
    def draw_grid_bg(self):
        for r in range(ROWS):
            for c in range(COLS):
                x = GRID_X + c * CELL
                y = GRID_Y + r * CELL
                col = (25, 25, 55) if (r+c) % 2 == 0 else (20, 20, 45)
                pygame.draw.rect(self.screen, col, (x, y, CELL, CELL))
                pygame.draw.rect(self.screen, GRID_COL, (x, y, CELL, CELL), 1)

    def draw_orbs(self):
        for r in range(ROWS):
            for c in range(COLS):
                orb = self.grid[r][c]
                if orb:
                    cx = GRID_X + c * CELL + CELL // 2
                    cy = GRID_Y + r * CELL + CELL // 2 + int(orb.y_off)
                    sel  = self.selected == (r, c)
                    hint = (self.hint_pair and
                            ((r,c) == (self.hint_pair[0], self.hint_pair[1]) or
                             (r,c) == (self.hint_pair[2], self.hint_pair[3])))
                    orb.draw(self.screen, cx, cy, selected=sel, hint=hint)

    def draw_panel(self):
        px = GRID_X + COLS * CELL + MARGIN
        pw = PANEL_W - MARGIN
        ph = WIN_H - MARGIN * 2

        pygame.draw.rect(self.screen, DARK_PANEL, (px, MARGIN, pw, ph), border_radius=12)
        pygame.draw.rect(self.screen, HIGHLIGHT,  (px, MARGIN, pw, ph), 2, border_radius=12)

        y = MARGIN + 20
        def label(text, colour, size='med'):
            nonlocal y
            f = self.font_med if size == 'med' else self.font_small
            s = f.render(text, True, colour)
            self.screen.blit(s, (px + 15, y))
            y += s.get_height() + 6

        label("NOVA CRUSH", CYAN, 'med')
        y += 10
        label(f"LEVEL  {self.level} / {self.level}", YELLOW)
        label(f"SCORE  {self.score}", WHITE)
        label(f"GOAL   {self.level * LEVEL_GOAL}", GREEN)
        label(f"MOVES  {self.moves}", ORANGE if self.moves <= 5 else WHITE)
        y += 10
        label(f"COMBO  x{self.combo}", MAGENTA)

        # progress bar
        y += 10
        bar_w = pw - 30
        prog  = min(1.0, self.score / (self.level * LEVEL_GOAL))
        pygame.draw.rect(self.screen, GRID_COL, (px+15, y, bar_w, 18), border_radius=9)
        pygame.draw.rect(self.screen, GREEN,
                         (px+15, y, int(bar_w * prog), 18), border_radius=9)
        pygame.draw.rect(self.screen, WHITE, (px+15, y, bar_w, 18), 1, border_radius=9)
        y += 30

        label("CONTROLS", CYAN)
        label("Click orb to select", WHITE, 'small')
        label("Click neighbour to swap", WHITE, 'small')
        label("H  - show hint", YELLOW, 'small')
        label("R  - restart", RED, 'small')
        label("ESC - quit", WHITE, 'small')

    def draw_top_bar(self):
        title = self.font_big.render("** NOVA CRUSH **", True, CYAN)
        self.screen.blit(title, (GRID_X, 8))

    def draw_particles(self):
        for p in self.particles:
            p.draw(self.screen)

    def draw_score_popups(self):
        for txt, x, y, life in self.score_popups:
            alpha = min(255, life * 6)
            col   = (*YELLOW, alpha)
            s = pygame.Surface((300, 30), pygame.SRCALPHA)
            rendered = self.font_med.render(txt, True, col)
            s.blit(rendered, (0, 0))
            self.screen.blit(s, (x - 50, y - (60 - life)))

    def draw_overlay(self, title, subtitle, colour):
        overlay = pygame.Surface((WIN_W, WIN_H), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 160))
        self.screen.blit(overlay, (0, 0))

        t1 = self.font_big.render(title, True, colour)
        t2 = self.font_med.render(subtitle, True, WHITE)
        t3 = self.font_small.render("Press R to restart  |  ESC to quit", True, CYAN)

        cx = WIN_W // 2
        cy = WIN_H // 2
        self.screen.blit(t1, t1.get_rect(center=(cx, cy - 50)))
        self.screen.blit(t2, t2.get_rect(center=(cx, cy + 10)))
        self.screen.blit(t3, t3.get_rect(center=(cx, cy + 60)))

    def draw_rules(self):
        self.screen.fill(BG)
        lines = [
            ("NOVA CRUSH  -  Rules", CYAN, 'big'),
            ("", WHITE, 'small'),
            ("Match 3 or more orbs of the same colour", WHITE, 'med'),
            ("by swapping adjacent orbs.", WHITE, 'med'),
            ("", WHITE, 'small'),
            ("* Click an orb, then click a neighbour to swap.", YELLOW, 'small'),
            ("* Chain reactions earn COMBO bonuses!", MAGENTA, 'small'),
            ("* Reach the score GOAL before moves run out.", GREEN, 'small'),
            ("* 5 levels of increasing difficulty.", ORANGE, 'small'),
            ("* Press H for a hint.", CYAN, 'small'),
            ("", WHITE, 'small'),
            ("Press SPACE or ENTER to start!", WHITE, 'med'),
        ]
        y = 80
        for text, colour, size in lines:
            if size == 'big':
                f = self.font_big
            elif size == 'med':
                f = self.font_med
            else:
                f = self.font_small
            s = f.render(text, True, colour)
            self.screen.blit(s, (60, y))
            y += s.get_height() + 10

        pygame.display.flip()

    # ── main draw ───────────────────────────────────────────────────
    def draw(self):
        self.screen.fill(BG)
        self.draw_top_bar()
        self.draw_grid_bg()
        self.draw_orbs()
        self.draw_particles()
        self.draw_score_popups()
        self.draw_panel()

        if self.state == "gameover":
            self.draw_overlay("GAME OVER",
                              f"Final score: {self.score}", RED)
        elif self.state == "win":
            self.draw_overlay("YOU WIN!",
                              f"Amazing! Score: {self.score}", GREEN)

        pygame.display.flip()

    # ── event handling ──────────────────────────────────────────────
    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit(); sys.exit()

            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_ESCAPE:
                    pygame.quit(); sys.exit()
                if self.state == "rules":
                    if event.key in (pygame.K_SPACE, pygame.K_RETURN):
                        self.state = "playing"
                        play_melody([(261,0.1),(329,0.1),(392,0.1),(523,0.2)])
                elif self.state in ("playing", "gameover", "win"):
                    if event.key == pygame.K_r:
                        self.init_game()
                        self.state = "playing"
                        play_melody([(261,0.1),(329,0.1),(392,0.1),(523,0.2)])
                    if event.key == pygame.K_h and self.state == "playing":
                        self.hint_pair  = self.find_hint()
                        self.hint_timer = 120
                        play_tone(600, 0.1)

            if event.type == pygame.MOUSEBUTTONDOWN and self.state == "playing":
                cell = self.pixel_to_cell(*event.pos)
                if cell:
                    r, c = cell
                    if self.selected is None:
                        self.selected = (r, c)
                        play_tone(520, 0.07)
                    else:
                        r1, c1 = self.selected
                        self.selected = None
                        if (r1, c1) != (r, c):
                            self.try_swap(r1, c1, r, c)
                        else:
                            play_tone(400, 0.05)

    # ── run ─────────────────────────────────────────────────────────
    def run(self):
        print("NOVA CRUSH started!")
        print("Rules: Match 3+ orbs by swapping neighbours.")
        print("Reach the score goal before moves run out.")
        print("Press H for hints, R to restart, ESC to quit.")

        while True:
            if self.state == "rules":
                self.draw_rules()
                self.handle_events()
            else:
                self.handle_events()
                self.update()
                self.draw()
            self.clock.tick(FPS)

